const now = new Date();
const currentYear = now.getFullYear();
const month = now.getMonth() + 1; // 1-12

// FY: April 1 to March 31
let fyStart, fyEnd;
if (month < 4) {
  // We're in Jan/Feb/Mar before FY close
  fyStart = currentYear - 1;
  fyEnd = currentYear;
} else {
  // After April
  fyStart = currentYear;
  fyEnd = currentYear + 1;
}

const financialYear = `${fyStart}-${String(fyEnd).slice(-2)}`;
const assessmentYear = `${fyEnd}-${String(fyEnd + 1).slice(-2)}`;

return [{
  json: {
    fy_start: fyStart,
    fy_end: fyEnd,
    financial_year: financialYear,
    assessment_year: assessmentYear
  }
}]

const emp = $input.all()[0].json;
const fy = $input.all()[1].json;
const salaryData = $input.all()[2]?.json || [];

// Calculate annual totals
const gross = salaryData.reduce((s, r) => s + parseFloat(r.gross_earnings || 0), 0);
const basic = salaryData.reduce((s, r) => s + parseFloat(r.basic_salary || 0), 0);
const hra = salaryData.reduce((s, r) => s + parseFloat(r.hra || 0), 0);
const tds = salaryData.reduce((s, r) => s + parseFloat(r.tds || 0), 0);
const pf = salaryData.reduce((s, r) => s + parseFloat(r.pf_employee || 0), 0);

// HRA exemption (40% of basic for non-metro)
const hraExempt = Math.min(hra, basic * 0.4);

// Standard deduction (old regime)
const stdDeduction = 50000;

// 80C (PF is eligible - max 1.5L)
const c80 = Math.min(pf, 150000);

// Taxable income calculation (old regime)
const exemptAllow = hraExempt;
const balanceIncome = gross - exemptAllow;
const taxableIncome = balanceIncome - stdDeduction - c80;

// Tax calculation (old regime slabs)
let tax = 0;
let remaining = taxableIncome;

if (taxableIncome <= 250000) {
  tax = 0;
} else if (taxableIncome <= 500000) {
  tax = (taxableIncome - 250000) * 0.05;
} else if (taxableIncome <= 1000000) {
  tax = 12500 + (taxableIncome - 500000) * 0.2;
} else {
  tax = 112500 + (taxableIncome - 1000000) * 0.3;
}

// Rebate 87A (if taxable <= 5L)
const rebate = taxableIncome <= 500000 ? Math.min(tax, 12500) : 0;
const taxAfterRebate = tax - rebate;

// 4% cess
const cess = taxAfterRebate * 0.04;
const totalTax = taxAfterRebate + cess;

// Tax payable/refund
const taxPayable = totalTax - tds;

return [{
  json: {
    employee_id: emp.employee_id,
    full_name: emp.full_name,
    pan_number: emp.pan_number,
    team_id: emp.team_id,
    financial_year: fy.financial_year,
    assessment_year: fy.assessment_year,
    fy_start: fy.fy_start,
    fy_end: fy.fy_end,
    // Income
    gross_salary: gross,
    exempt_allowances: exemptAllow,
    balance_income: balanceIncome,
    deductions_std: stdDeduction,
    chapter_vi_a: c80,
    taxable_income: taxableIncome,
    // Tax
    tax_on_income: tax,
    rebate_87a: rebate,
    tax_after_rebate: taxAfterRebate,
    cess_4: cess,
    total_tax: totalTax,
    total_tds_deducted: tds,
    tax_payable_refund: taxPayable
  }
}]

